import PizZip from 'pizzip';
import Docxtemplater from 'docxtemplater';

export async function generateWordDocument(documentData, procedureData) {
    try {
        // Crear documento base con estructura válida
        const docContent = generateBaseDocument(documentData, procedureData);
        
        // Crear blob del documento
        const blob = new Blob([docContent], {
            type: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
        });
        
        // Descargar
        const fileName = `${documentData.headerConfig?.policyName || 'Procedimiento'}.docx`;
        
        if (window.navigator && window.navigator.msSaveOrOpenBlob) {
            window.navigator.msSaveOrOpenBlob(blob, fileName);
        } else {
            const url = URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.download = fileName;
            link.style.display = 'none';
            document.body.appendChild(link);
            link.click();
            setTimeout(() => {
                document.body.removeChild(link);
                URL.revokeObjectURL(url);
            }, 100);
        }
        
        return true;
    } catch (error) {
        console.error('Error generando documento:', error);
        throw error;
    }
}

function generateBaseDocument(documentData, procedureData) {
    const formattedDate = formatDate(new Date(documentData.headerConfig?.fecha || new Date()));
    
    return `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
