    }

    return `<w:p w:rsidR="00A87A6F" w:rsidRDefault="00A87A6F">
        <w:r>
            <w:t>${escapeXML(cleanContent)}</w:t>
        </w:r>
    </w:p>`;
}

// Secciones del documento
function generateObjectiveSection(content) {
    return `<w:p w:rsidR="00A87A6F" w:rsidRDefault="00A87A6F">
        <w:pPr><w:pStyle w:val="Heading1"/></w:pPr>
        <w:r><w:t>1. Objetivo o Propósito</w:t></w:r>
