function getBackgroundColor(level) {
    const colors = {
        'sub': 'E8F5E8',
        'section': 'E3F2FD',
        'question': 'FFF3CD',
        'alternative': 'D1ECF1',
        'end': 'D4EDDA'
    };
    return colors[level] || '';
}
